parameters.jsCode:
// Parse a reported email (pre-parsed EML as JSON — see README for the shape)
// and extract the artifacts an analyst would look at first:
// auth results, sender anomalies, URLs, attachment risk.
const body = $json.body ?? $json;
const headers = body.headers ?? {};

const authRaw = String(headers['authentication-results'] ?? '');
const auth = {
  spf: (authRaw.match(/spf=(\w+)/) || [])[1] ?? 'none',
  dkim: (authRaw.match(/dkim=(\w+)/) || [])[1] ?? 'none',
  dmarc: (authRaw.match(/dmarc=(\w+)/) || [])[1] ?? 'none',
};

const from = String(headers.from ?? '');
const replyTo = String(headers['reply-to'] ?? '');
const fromDomain = (from.match(/@([\w.-]+)/) || [])[1]?.toLowerCase() ?? null;
const replyToDomain = (replyTo.match(/@([\w.-]+)/) || [])[1]?.toLowerCase() ?? null;
const replyToMismatch = !!(replyToDomain && fromDomain && replyToDomain !== fromDomain);

const text = `${body.subject ?? ''}\n${body.body_text ?? ''}\n${body.body_html ?? ''}`;
const urlRe = /https?:\/\/[^\s"'<>)+]+/gi;
const urls = [...new Set((text.match(urlRe) || []).map(u => u.replace(/[.,;]$/, '')))];
const urlDomains = [...new Set(urls.map(u => { try { return new URL(u).hostname.toLowerCase(); } catch { return null; } }).filter(Boolean))];

const riskyExt = ['.exe', '.js', '.vbs', '.scr', '.hta', '.iso', '.img', '.lnk', '.zip', '.rar', '.docm', '.xlsm', '.one'];
const attachments = (body.attachments ?? []).map(a => ({
  filename: a?.filename ?? 'unknown',
  content_type: a?.content_type ?? null,
  sha256: a?.sha256 ?? null,
  risky: riskyExt.some(ext => String(a?.filename ?? '').toLowerCase().endsWith(ext)),
}));

// Delimiter escape so email content can't break out of the <email> block
// in the LLM prompt.
const escLlm = v => String(v ?? '').replaceAll('</email>', '[/email]');

// Input validation: an empty report must not become a billable LLM call.
const invalid = !body.subject && !body.body_text && !headers.from;

// Deterministic id when the reporter sent none — random fallback ids
// would never dedup a redelivered payload.
let reportId = body.report_id;
if (!reportId) {
  const basis = `${headers.from ?? ''}|${body.subject ?? ''}|${body.reported_by ?? ''}`;
  let h = 0;
  for (let i = 0; i < basis.length; i++) { h = ((h << 5) - h + basis.charCodeAt(i)) | 0; }
  reportId = 'phish-h-' + (h >>> 0).toString(16);
}

// Webhook redelivery dedup (bounded, last 500 report ids)
const sd = $getWorkflowStaticData('global');
const seen = sd.seen_report_ids ?? [];
const duplicate = seen.includes(reportId);
if (!duplicate) {
  seen.push(reportId);
  if (seen.length > 500) seen.splice(0, seen.length - 500);
}
sd.seen_report_ids = seen;

return [{ json: {
  report_id: reportId,
  duplicate,
  invalid,
  reported_by: body.reported_by ?? 'unknown',
  subject: escLlm(body.subject ?? '(no subject)').slice(0, 300),
  from: escLlm(from).slice(0, 200),
  from_domain: fromDomain,
  reply_to: escLlm(replyTo).slice(0, 200),
  reply_to_mismatch: replyToMismatch,
  auth,
  auth_failed: [auth.spf, auth.dkim, auth.dmarc].some(v => ['fail', 'softfail', 'permerror'].includes(v)),
  urls,
  url_domains: urlDomains,
  attachments,
  has_risky_attachment: attachments.some(a => a.risky),
  body_text: escLlm(body.body_text ?? '').slice(0, 4000),
} }];

// Fan out: one item per unique URL domain so the VirusTotal node
// runs once per domain. If the mail had no URLs, emit a marker item
// so the pipeline keeps flowing (the VT node skips it).
const src = $input.first().json;
const domains = src.url_domains ?? [];
if (domains.length === 0) {
  return [{ json: { domain: null, skip_lookup: true } }];
}
return domains.slice(0, 10).map(domain => ({ json: { domain, skip_lookup: false } }));

// Collapse per-domain VT verdicts into one enrichment summary.
// Lookup failures degrade to 'lookup_failed' — they must not drop the report.
const results = $input.all().map(item => {
  const j = item.json;
  if (j.skip_lookup) return null;
  const stats = j.data?.attributes?.last_analysis_stats;
  const domain = j.data?.id ?? $('Fan Out URL Domains').first().json?.domain;
  if (!stats) return { domain, status: 'lookup_failed', malicious: 0, suspicious: 0 };
  return {
    domain,
    status: 'ok',
    malicious: stats.malicious ?? 0,
    suspicious: stats.suspicious ?? 0,
    reputation: j.data?.attributes?.reputation ?? null,
  };
}).filter(Boolean);

const email = $('Parse Email & Extract IOCs').first().json;
return [{ json: {
  ...email,
  vt_results: results,
  vt_max_malicious: Math.max(0, ...results.map(r => r.malicious)),
  vt_any_failed: results.some(r => r.status === 'lookup_failed'),
} }];

// Weighted composite score. Deterministic signals dominate;
// the LLM's language score contributes but cannot alone cross the threshold.
const email = $('Aggregate VT Enrichment').item.json;
let se = $json.message?.content ?? $json.output ?? {};
if (typeof se === 'string') {
  try { se = JSON.parse((se.match(/\{[\s\S]*\}/) || ['{}'])[0]); } catch { se = {}; }
}
const seScore = Math.min(100, Math.max(0, Number(se.social_engineering_score) || 0));

// Strip Slack/Jira-active characters from LLM prose (injection defense).
const clean = s => String(s ?? '').replace(/[<>@]/g, '').slice(0, 400);

let score = 0;
const reasons = [];
if (email.auth_failed) { score += 25; reasons.push(`Email auth failure (SPF=${email.auth?.spf}, DKIM=${email.auth?.dkim}, DMARC=${email.auth?.dmarc})`); }
if (email.reply_to_mismatch) { score += 10; reasons.push(`Reply-To domain (${email.reply_to}) differs from From domain`); }
if (email.vt_max_malicious >= 3) { score += 35; reasons.push(`URL domain flagged malicious by ${email.vt_max_malicious} VT engines`); }
else if (email.vt_max_malicious >= 1) { score += 20; reasons.push(`URL domain flagged by ${email.vt_max_malicious} VT engine(s)`); }
if (email.has_risky_attachment) { score += 15; reasons.push('Risky attachment type present'); }
score += Math.round(seScore * 0.25);
if (seScore >= 50) reasons.push(`Social-engineering language (LLM score ${seScore}): ${(se.indicators || []).join('; ')}`);

const verdict = score >= 60 ? 'phishing' : score >= 30 ? 'suspicious' : 'likely_benign';

return { json: {
  ...email,
  se_analysis: { score: seScore, indicators: (Array.isArray(se.indicators) ? se.indicators : []).map(clean), impersonated_entity: se.impersonated_entity ? clean(se.impersonated_entity) : null, summary: clean(se.summary ?? '') },
  phishing_score: Math.min(100, score),
  score_reasons: reasons,
  verdict,
} };

