=Reported by: {{ $json.reported_by ?? 'unknown' }}
From: {{ $json.from ?? 'n/a' }}
Reply-To: {{ $json.reply_to || 'n/a' }}
Auth: SPF={{ $json.auth?.spf ?? 'n/a' }} DKIM={{ $json.auth?.dkim ?? 'n/a' }} DMARC={{ $json.auth?.dmarc ?? 'n/a' }}

Score: {{ $json.phishing_score ?? 0 }}/100 — verdict: {{ $json.verdict ?? 'n/a' }}
Reasons:
{{ ($json.score_reasons ?? []).map(r => '- ' + r).join('\n') }}

LLM summary: {{ $json.se_analysis?.summary ?? 'n/a' }}
Impersonated entity: {{ $json.se_analysis?.impersonated_entity || 'n/a' }}

URLs:
{{ ($json.urls ?? []).map(u => '- ' + u).join('\n') || '(none)' }}

VirusTotal:
{{ ($json.vt_results ?? []).map(r => `- ${r?.domain}: ${r?.status === 'ok' ? r?.malicious + ' malicious engines' : 'lookup failed'}`).join('\n') || '(no lookups)' }}

Attachments:
{{ ($json.attachments ?? []).map(a => `- ${a?.filename}${a?.risky ? ' ⚠ risky type' : ''} (sha256: ${a?.sha256 || 'n/a'})`).join('\n') || '(none)' }}

