parameters.jsCode:
// Structured audit record (bounded) — production: audit table insert.
const src = $('Compute Phishing Score').first().json;
let ticket = null;
try { ticket = $('Jira: Open Phishing Ticket').item.json?.key ?? null; } catch (e) {}
const sd = $getWorkflowStaticData('global');
const log = sd.audit_log ?? [];
log.push({
  ts: new Date().toISOString(),
  workflow: '02-phishing-email-triage',
  report_id: src.report_id ?? null,
  verdict: src.verdict ?? null,
  phishing_score: src.phishing_score ?? null,
  ticket,
  delivery_ok: !$json.error,
  delivery_error: $json.error ? String($json.error.message ?? $json.error).slice(0, 200) : null,
});
if (log.length > 300) log.splice(0, log.length - 300);
sd.audit_log = log;
return { json: $json };
